"use client";

import React, { useRef, useState, useEffect } from "react";
import { motion } from "framer-motion";
import { cn } from "../lib/utils";

// ==========================================
// 1. THE VOID BUTTON
// ==========================================
export function VoidButton({ className, children, ...props }: React.ButtonHTMLAttributes<HTMLButtonElement>) {
  const containerRef = useRef<HTMLButtonElement>(null);
  const [mousePos, setMousePos] = useState({ x: 0, y: 0 });
  const [isHovered, setIsHovered] = useState(false);

  const handleMouseMove = (e: React.MouseEvent<HTMLButtonElement>) => {
    if (!containerRef.current) return;
    const rect = containerRef.current.getBoundingClientRect();
    setMousePos({
      x: e.clientX - rect.left,
      y: e.clientY - rect.top,
    });
  };

  return (
    <button
      ref={containerRef}
      onMouseMove={handleMouseMove}
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
      className={cn(
        "relative w-48 h-12 rounded border border-neutral-900 bg-black font-mono text-xs uppercase tracking-widest cursor-pointer select-none overflow-hidden outline-none transition-colors duration-300",
        className
      )}
      style={{
        boxShadow: "inset 0 3px 8px rgba(0,0,0,0.95), inset 0 -1px 2px rgba(255,255,255,0.04), 0 1px 1px rgba(0,0,0,0.5)",
      }}
      {...props}
    >
      {/* Base Layer: White text on black */}
      <span className="absolute inset-0 flex items-center justify-center text-white/90 font-bold transition-opacity duration-300">
        {children || "THE VOID"}
      </span>

      {/* Active Reveal Layer: Dark text on luxury gold gradient */}
      <motion.div
        className="absolute inset-0 pointer-events-none bg-gradient-to-r from-[#ffe066] via-[#f39c12] to-[#ffffff] flex items-center justify-center"
        initial={{ opacity: 0 }}
        animate={{ opacity: isHovered ? 1 : 0 }}
        transition={{ duration: 0.3 }}
        style={{
          WebkitMaskImage: `radial-gradient(circle 65px at ${mousePos.x}px ${mousePos.y}px, black 25%, transparent 100%)`,
          maskImage: `radial-gradient(circle 65px at ${mousePos.x}px ${mousePos.y}px, black 25%, transparent 100%)`,
        }}
      >
        <span className="text-black font-black">
          {children || "THE VOID"}
        </span>
      </motion.div>
    </button>
  );
}

// ==========================================
// 2. THE BRUSHED TITANIUM BUTTON
// ==========================================
export function BrushedTitaniumButton({ className, children, ...props }: React.ButtonHTMLAttributes<HTMLButtonElement>) {
  const containerRef = useRef<HTMLButtonElement>(null);
  const [mousePos, setMousePos] = useState({ x: 0, y: 0 });
  const [isHovered, setIsHovered] = useState(false);
  const [btnWidth, setBtnWidth] = useState(192);

  useEffect(() => {
    if (containerRef.current) {
      setBtnWidth(containerRef.current.offsetWidth || 192);
    }
  }, []);

  const handleMouseMove = (e: React.MouseEvent<HTMLButtonElement>) => {
    if (!containerRef.current) return;
    const rect = containerRef.current.getBoundingClientRect();
    setMousePos({
      x: e.clientX - rect.left,
      y: e.clientY - rect.top,
    });
  };

  const highlightX = (mousePos.x / btnWidth) * 100;

  return (
    <button
      ref={containerRef}
      onMouseMove={handleMouseMove}
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
      className={cn(
        "relative w-48 h-12 rounded font-mono text-xs uppercase tracking-widest cursor-pointer select-none overflow-hidden outline-none border border-neutral-700/60 bg-neutral-900 transition-shadow duration-300",
        className
      )}
      style={{
        backgroundImage: "linear-gradient(to bottom, #2c2c2e, #1c1c1e)",
        boxShadow: isHovered 
          ? "0 6px 16px rgba(0,0,0,0.5), inset 0 1px 0 rgba(255,255,255,0.25)"
          : "0 3px 8px rgba(0,0,0,0.4), inset 0 1px 0 rgba(255,255,255,0.15)",
      }}
      {...props}
    >
      {/* Brushed Micro-lines Overlay */}
      <div 
        className="absolute inset-0 opacity-40 mix-blend-overlay pointer-events-none"
        style={{
          backgroundImage: "repeating-linear-gradient(0deg, rgba(255,255,255,0.06) 0px, rgba(255,255,255,0.06) 1px, transparent 1px, transparent 2px)"
        }}
      />

      {/* Dynamic Anisotropic Sweep highlight */}
      <div 
        className="absolute inset-0 pointer-events-none opacity-40 transition-opacity duration-300"
        style={{
          opacity: isHovered ? 0.75 : 0.4,
          background: `linear-gradient(115deg, transparent 35%, rgba(255,255,255,0.12) 48%, rgba(255,255,255,0.25) 50%, rgba(255,255,255,0.12) 52%, transparent 65%)`,
          backgroundSize: "200% 100%",
          backgroundPosition: `${highlightX}% 50%`,
          transition: "background-position 0.05s ease"
        }}
      />

      {/* Spot Flashlight Highlight */}
      <div 
        className="absolute inset-0 pointer-events-none transition-opacity duration-300"
        style={{
          opacity: isHovered ? 1 : 0,
          background: `radial-gradient(circle 80px at ${mousePos.x}px ${mousePos.y}px, rgba(255, 255, 255, 0.08), transparent)`
        }}
      />

      {/* Button Text */}
      <span className="relative z-10 flex items-center justify-center h-full text-neutral-300 font-bold tracking-widest text-shadow-sm">
        {children || "TITANIUM"}
      </span>
    </button>
  );
}

